    public async Task<MarkLeadExportedResult> MarkLeadExportedAsync(Guid leadId, DateTimeOffset exportedAtUtc)
    {
        var affected = await db.PresaleLeads.Where(x => x.Id == leadId && x.ExportedAt == null)
                                            .ExecuteUpdateAsync(x => x.SetProperty(p => p.ExportedAt, exportedAtUtc)
                                                                      .SetProperty(p => p.UpdatedAt, DateTimeOffset.UtcNow));

        if (affected == 1)
        {
            return new MarkLeadExportedResult(true, null, null, exportedAtUtc);
        }

        var existingLead = await db.PresaleLeads.AsNoTracking().SingleOrDefaultAsync(x => x.Id == leadId);
        if (existingLead is null)
        {
            return new MarkLeadExportedResult(false, "LEAD_NOT_FOUND", "Presale lead was not found.", null);
        }

        return new MarkLeadExportedResult(false, "ALREADY_EXPORTED", "Presale lead was already exported.", existingLead.ExportedAt);
    }

    public async Task<DiscoveryQuestionAddResult> AddDiscoveryQuestionWithLimitAsync(Guid leadId, DiscoveryQuestion question, int maxQuestions = 5)
    {
        await using var tx = await db.Database.BeginTransactionAsync(System.Data.IsolationLevel.Serializable);

        var now = DateTimeOffset.UtcNow;
        var affected = await db.PresaleLeads.Where(x => x.Id == leadId && x.DiscoveryQuestionCount < maxQuestions)
                                            .ExecuteUpdateAsync(x => x.SetProperty(p => p.DiscoveryQuestionCount, p => p.DiscoveryQuestionCount + 1)
                                                                      .SetProperty(p => p.UpdatedAt, now));

        if (affected == 0)
        {
            var existingLead = await db.PresaleLeads.SingleOrDefaultAsync(x => x.Id == leadId);
            if (existingLead is null)
            {
                await tx.RollbackAsync();

                return new DiscoveryQuestionAddResult(false, "LEAD_NOT_FOUND", "Presale lead was not found.", 0, null);
            }

            await tx.RollbackAsync();

            return new DiscoveryQuestionAddResult(false, "DISCOVERY_LIMIT_REACHED", $"Discovery question limit of {maxQuestions} has been reached.", existingLead.DiscoveryQuestionCount, null);
        }

        var lead = await db.PresaleLeads.SingleAsync(x => x.Id == leadId);

        question.PresaleLeadId = leadId;
        question.Id = question.Id == Guid.Empty ? Guid.NewGuid() : question.Id;
        question.Sequence = lead.DiscoveryQuestionCount;
        question.RoundNumber = Math.Max(0, question.RoundNumber);
        question.CreatedAt = now;

        var added = await db.DiscoveryQuestions.AddAsync(question);
        await db.SaveChangesAsync();
        await tx.CommitAsync();

        return new DiscoveryQuestionAddResult(true, null, null, lead.DiscoveryQuestionCount, added.Entity);
    }

