        askedQuestion.RoundNumber = Math.Max(0, askedQuestion.RoundNumber);
        askedQuestion.QuestionTopicKey = string.IsNullOrWhiteSpace(askedQuestion.QuestionTopicKey)
            ? "unknown"
            : askedQuestion.QuestionTopicKey.Trim().ToLowerInvariant();

        var existing = await db.AskedQuestions
            .SingleOrDefaultAsync(x => x.PresaleLeadId == leadId
                                    && x.QuestionTopicKey == askedQuestion.QuestionTopicKey
                                    && x.RoundNumber == askedQuestion.RoundNumber);
        if (existing is not null)
        {
            return existing;
        }

        askedQuestion.AskedAtUtc = DateTimeOffset.UtcNow;

        var added = await db.AskedQuestions.AddAsync(askedQuestion);
        try
        {
            await db.SaveChangesAsync();
        }
        catch (DbUpdateException ex) when (IsUniqueConstraintViolation(ex))
        {
            var concurrentExisting = await db.AskedQuestions
                .SingleOrDefaultAsync(x => x.PresaleLeadId == leadId
