    public async Task<AskedQuestionBatchAddResult> AddAskedQuestionsBatchAsync(Guid leadId, IReadOnlyList<AskedQuestion> askedQuestions)
    {
        if (askedQuestions.Count == 0)
        {
            return new AskedQuestionBatchAddResult(true, null, null, []);
        }

        await using var tx = await db.Database.BeginTransactionAsync(System.Data.IsolationLevel.Serializable);

        var leadExists = await db.PresaleLeads.AnyAsync(x => x.Id == leadId);
        if (!leadExists)
        {
            await tx.RollbackAsync();

            return new AskedQuestionBatchAddResult(false, "LEAD_NOT_FOUND", "Presale lead was not found.", []);
        }

        var now = DateTimeOffset.UtcNow;
        var normalized = new List<AskedQuestion>(askedQuestions.Count);
        foreach (var askedQuestion in askedQuestions)
        {
            askedQuestion.PresaleLeadId = leadId;
            askedQuestion.Id = askedQuestion.Id == Guid.Empty ? Guid.NewGuid() : askedQuestion.Id;
            askedQuestion.RoundNumber = Math.Max(0, askedQuestion.RoundNumber);
            askedQuestion.QuestionTopicKey = string.IsNullOrWhiteSpace(askedQuestion.QuestionTopicKey)
                ? "unknown"
                : askedQuestion.QuestionTopicKey.Trim().ToLowerInvariant();
            askedQuestion.AskedAtUtc = now;
            normalized.Add(askedQuestion);
        }

        var distinctByKey = normalized
            .GroupBy(x => (x.QuestionTopicKey, x.RoundNumber))
            .Select(x => x.First())
            .ToList();

        var rounds = distinctByKey.Select(x => x.RoundNumber).Distinct().ToList();
        var topics = distinctByKey.Select(x => x.QuestionTopicKey).Distinct(StringComparer.OrdinalIgnoreCase).ToList();

        var existingKeys = await db.AskedQuestions
            .Where(x => x.PresaleLeadId == leadId && rounds.Contains(x.RoundNumber) && topics.Contains(x.QuestionTopicKey))
            .Select(x => new { x.QuestionTopicKey, x.RoundNumber })
            .ToListAsync();

        var existingSet = existingKeys
            .Select(x => (x.QuestionTopicKey, x.RoundNumber))
            .ToHashSet();

        var toInsert = distinctByKey
            .Where(x => !existingSet.Contains((x.QuestionTopicKey, x.RoundNumber)))
            .ToList();

        if (toInsert.Count == 0)
        {
            await tx.RollbackAsync();

            return new AskedQuestionBatchAddResult(true, null, null, []);
        }

        await db.AskedQuestions.AddRangeAsync(toInsert);
        try
        {
            await db.SaveChangesAsync();
            await tx.CommitAsync();

            return new AskedQuestionBatchAddResult(true, null, null, toInsert);
        }
        catch (DbUpdateException ex) when (IsUniqueConstraintViolation(ex))
        {
            await tx.RollbackAsync();

            var keys = toInsert
                .Select(x => (x.QuestionTopicKey, x.RoundNumber))
                .ToHashSet();

            var recoveryRounds = keys.Select(x => x.RoundNumber).Distinct().ToList();
            var recoveryTopics = keys.Select(x => x.QuestionTopicKey).Distinct(StringComparer.OrdinalIgnoreCase).ToList();

            var recovered = await db.AskedQuestions
                .Where(x => x.PresaleLeadId == leadId && recoveryRounds.Contains(x.RoundNumber) && recoveryTopics.Contains(x.QuestionTopicKey))
                .ToListAsync();

            var recoveredForKeys = recovered
                .Where(x => keys.Contains((x.QuestionTopicKey, x.RoundNumber)))
                .ToList();

            return new AskedQuestionBatchAddResult(true, null, null, recoveredForKeys);
        }
    }

    public async Task<IEnumerable<AskedQuestion>> GetAskedQuestionsAsync(Guid leadId)
    {
        var askedQuestions = await db.AskedQuestions.Where(x => x.PresaleLeadId == leadId)
                                                    .ToListAsync();

        askedQuestions.Sort((left, right) => left.AskedAtUtc.CompareTo(right.AskedAtUtc));

        return askedQuestions;
    }

    private static string? AppendTranscript(string? existingTranscript, string? newTranscript)
    {
        if (string.IsNullOrWhiteSpace(newTranscript))
        {
            return existingTranscript;
        }

        var sb = new StringBuilder();
        sb.AppendLine(existingTranscript ?? string.Empty);
        sb.AppendLine();
        sb.AppendLine(newTranscript);

        return sb.ToString();
    }

    private static bool IsUniqueConstraintViolation(DbUpdateException ex)
    {
        return ex.InnerException is SqliteException sqliteException
            && sqliteException.SqliteErrorCode == 19;
    }
